  function installationSpecRows(c){const e=c.elevatorInfo||{},i=c.installationInfo||{},count=e.count||"1",door=e.doorType||"أوتوماتيك";return [["نوع المصعد",door],["الاستخدام",e.usage||"ركاب"],["عدد المصاعد",count],["عدد الوقفات",i.stops||e.age||"حسب الموقع"],["عدد المداخل",i.entrances||"حسب الموقع"],["البطارية",i.battery||"حسب الاتفاق"],["VVVF",i.vvvf||"حسب الاتفاق"],["الحمولة / السعة",e.capacity||"حسب المواصفات المتفق عليها"],["الماركة",e.brand||"حسب العرض المعتمد"],["فتحة الباب",i.doorOpening||"حسب الموقع"],["أبعاد البئر",i.shaftSize||"حسب الموقع"],["المكينة",i.motor||"حسب العرض المعتمد"],["الكنترول",i.controller||"حسب العرض المعتمد"],["الأبواب الخارجية",i.outerDoors||"حسب العرض المعتمد"],["باب الأمان الداخلي",i.safetyDoor||"حسب العرض المعتمد"],["الكابينة",i.cabin||"استانلس/زجاج أو حسب الاختيار المعتمد"],["نظام الكهرباء",i.power||"3 Phase 380v عند توفره"],["السرعة",i.speed||"حسب المواصفات"],["الضمان",i.warranty||"سنة من تاريخ التشغيل لا تشمل سوء الاستخدام"]].map(r=>`<tr><th>${r[0]}</th><td>${r[1]}</td></tr>`).join("")}
  function installationContractDetails(c){const company=c.company?.name||activeOwnerCompany()?.name||"شركة غير محددة",client=contractLabel(c),building=(c.buildings||[])[0]||{},install=c.installationInfo||{};return `<style>.installation-contract .contract-section:nth-of-type(2),.installation-contract .contract-section:nth-of-type(5),.installation-contract .contract-section:nth-of-type(7){break-before:page;page-break-before:always}.installation-contract .contract-section:nth-of-type(1),.installation-contract .contract-section:nth-of-type(2),.installation-contract .contract-section:nth-of-type(3),.installation-contract .contract-spec-table,.installation-contract .signature-grid section{break-inside:avoid;page-break-inside:avoid}.installation-contract h3{break-after:avoid;page-break-after:avoid}.installation-contract p{orphans:3;widows:3}@media screen{.installation-contract .contract-section{break-before:auto;page-break-before:auto}}</style><div class="contract-document installation-contract"><div class="contract-topline"><span class="contract-type">عرض وعقد توريد وتركيب مصعد</span>${badge(c.status)}</div><div class="installation-hero"><div><small>بسم الله الرحمن الرحيم</small><h3>عقد تركيب مصعد فل أوتوماتيك</h3><p>يسعدنا نحن ${company} أن نتقدم لسعادتكم بهذا العقد لتوريد وتركيب مصعد في موقعكم الموضح أدناه، وفق المواصفات الفنية والبنود العامة المعتمدة.</p></div><strong>${money(c.value)}</strong></div><div class="contract-summary"><div><small>السيد / الطرف الثاني</small><b>${client}</b></div><div><small>رقم العقد</small><b>${c.id}</b></div><div><small>الموقع</small><b>${building.name||"غير محدد"} ${building.district||""}</b></div><div><small>تاريخ العقد</small><b>${c.startDate||"غير محدد"}</b></div><div><small>الإجمالي شامل الضريبة</small><b>${money(c.value)}</b></div><div><small>منشأة الإصدار</small><b>${company}</b></div></div><section class="contract-section"><h3>البند الأول: نطاق التوريد والتركيب</h3><p>${c.details||"يشمل العقد توريد وتركيب المصعد والسكة والأبواب والكابينة والمكينة ولوحة التحكم والتشغيل والاختبار وفق المواصفات الفنية المعتمدة، ويشمل العرض ضريبة القيمة المضافة ما لم يذكر خلاف ذلك."}${install.note?`<br>${esc(install.note)}`:""}</p></section><section class="contract-section"><h3>البند الثاني: الدفعات</h3><table class="contract-spec-table"><thead><tr><th>الدفعة</th><th>البيان</th><th>القيمة</th></tr></thead><tbody>${installationPayments(c.value)}</tbody></table></section><section class="contract-section"><h3>البند الثالث: المواصفات الفنية</h3><table class="contract-spec-table"><tbody>${installationSpecRows(c)}</tbody></table></section><section class="contract-section"><h3>البند الرابع: المباني والمواقع</h3>${renderTerms((c.buildings||[]).map(b=>({section:"مواقع العقد",title:b.name,description:`${b.district||""} ${b.mapUrl||""}`})),"لا توجد مواقع.")}</section><section class="contract-section"><h3>البند الخامس: الأحكام العامة</h3><div class="contract-terms"><article><b>المرفقات</b><p>تعتبر أي مرفقات أو مواصفات أو رسومات موقعة من الطرفين جزءا لا يتجزأ من هذا العقد.</p></article><article><b>التأخير والتعديلات</b><p>أي تأخير في الأعمال التحضيرية أو الدفعات أو تعديل المناسيب وفتحات الأبواب قد يترتب عليه تمديد مدة التسليم وتحميل الطرف الثاني أي تكاليف إضافية لازمة.</p></article><article><b>نقل الملكية</b><p>لا يحق للطرف الثاني بيع أو نقل أو التنازل عن المصعد قبل سداد قيمة العقد كاملة، وعند انتقال ملكية العقار يتم تزويد الطرف الأول ببيانات المالك الجديد.</p></article><article><b>الخلافات</b><p>تسوى الخلافات وديا، وفي حال تعذر ذلك يكون الاختصاص للجهة القضائية المختصة في موقع المشروع.</p></article></div></section><section class="contract-section"><h3>البند السادس: التوريد والتركيب والضمان</h3><div class="contract-terms"><article><b>التزام الطرف الأول</b><p>يلتزم الطرف الأول بتوريد وتركيب المصعد حسب أصول الصنعة ومتطلبات السلامة المعمول بها في المملكة العربية السعودية.</p></article><article><b>إيقاف الأعمال</b><p>يحق للطرف الأول إيقاف أعمال التوريد أو التركيب عند عدم سداد الدفعات المستحقة أو عدم جاهزية الأعمال التحضيرية.</p></article><article><b>الضمان والصيانة</b><p>يبدأ الضمان من تاريخ تشغيل المصعد ولمدة سنة، ولا يشمل سوء الاستخدام. تبدأ الصيانة بعد سداد قيمة العقد كاملة واستلام المصعد.</p></article></div></section><section class="contract-section"><h3>البند السابع: الأعمال التحضيرية على الطرف الثاني</h3><div class="contract-terms"><article><b>بيت المصعد وغرفة المحرك</b><p>تجهيز بيت المصعد وغرفة المحرك والعزل والإنارة والتهوية وفتحات الأبواب حسب الأبعاد المعتمدة قبل بدء الأعمال.</p></article><article><b>التيار الكهربائي والمستودع</b><p>تأمين التيار الكهربائي المناسب ومكان آمن لحفظ أجزاء المصعد طوال فترة التركيب.</p></article><article><b>السقالة والتدريب</b><p>تأمين السقالة عند الحاجة، وتعيين من يراه الطرف الثاني مناسبا لتدريبه على إنزال الكابينة يدويا في حالات الطوارئ.</p></article></div></section><section class="contract-section"><h3>البنود الإضافية</h3>${renderTerms([...(c.items||[]),...(c.customItems||[])],"لا توجد بنود إضافية.")}</section>${companyStamp()}${pdfAction("contract",c.id)}</div>`}
  function contractDetails(c){if(c.type==="تركيب")return installationContractDetails(c);return `<div class="contract-document"><div class="contract-topline"><span class="contract-type">عقد ${c.type}</span>${badge(c.status)}</div><div class="contract-title"><div><span>وثيقة عقد رقم</span><b>${c.id}</b></div><strong>${money(c.value)}</strong></div><div class="contract-summary"><div><small>العميل / المنشأة</small><b>${contractLabel(c)}</b></div><div><small>بداية العقد</small><b>${c.startDate||"غير محدد"}</b></div><div><small>نهاية العقد</small><b>${c.endDate||"غير محدد"}</b></div><div><small>منشأة الإصدار</small><b>${c.company?.name||activeOwnerCompany()?.name||"غير محدد"}</b></div></div>${elevatorSection(c.elevatorInfo)}<section class="contract-section"><h3>المباني والمواقع</h3>${renderTerms((c.buildings||[]).map(b=>({section:"مواقع العقد",title:b.name,description:`${b.district||""} ${b.mapUrl||""}`})),"لا توجد مواقع.")}</section><section class="contract-section"><h3>البنود الافتراضية</h3>${renderTerms(c.items,"لا توجد بنود افتراضية.")}</section><section class="contract-section"><h3>البنود الإضافية</h3>${renderTerms(c.customItems,"لا توجد بنود إضافية.")}</section><section class="contract-section"><h3>نطاق العمل</h3><p>${c.details||"لا توجد تفاصيل إضافية."}</p></section>${companyStamp()}${pdfAction("contract",c.id)}</div>`}
  function ticketDetails(t){const loc=t.assignedTo?locations.find(l=>cleanId(l.identity)===cleanId(t.assignedTo)&&l.live):null;return `<div class="report-details"><dl><dt>العميل / المنشأة</dt><dd>${t.clientCompanyName||t.clientName||"غير محدد"}</dd><dt>رقم البلاغ</dt><dd>${t.id}</dd><dt>العنوان</dt><dd>${t.title}</dd><dt>الوصف</dt><dd>${t.description}</dd><dt>العقد</dt><dd>${t.contractId||"غير مرتبط"}</dd><dt>الموقع</dt><dd>${t.building?.name||"غير محدد"} ${t.building?.district||""}</dd><dt>الحالة</dt><dd>${t.status}</dd><dt>المسند إليه</dt><dd>${staff.find(s=>s.identity===t.assignedTo)?.name||t.assignedTo||"غير مسند"}</dd><dt>موقع الفني القادم</dt><dd>${loc?mapLink(loc.mapUrl,"عرض الموقع المباشر"):"غير متاح حاليًا"}</dd></dl></div>${elevatorSection(t.elevatorInfo)}${companyStamp()}${pdfAction("ticket",t.id)}`}
  function visitReport(v){return reports.find(r=>r.visitId===v.id)}
  function canWriteReport(v){return ["technician","engineer"].includes(session.role)&&cleanId(v.assignedTo)===cleanId(session.id)&&!visitReport(v)}
  function visitRoom(v){return `shumoos-${String(v.id||"visit").replace(/[^a-zA-Z0-9-]/g,"")}`}
  function visitCommunication(v){const c=contracts.find(x=>x.id===v.contractId)||{},tech=staff.find(s=>cleanId(s.identity)===cleanId(v.assignedTo))||{},msgs=visitMessages.filter(m=>m.visitId===v.id).slice(-50),room=visitRoom(v),meet=`https://meet.jit.si/${room}`,phone=tech.phone||tech.mobile||v.building?.guardMobile||c.buildings?.[0]?.guardMobile||"";return `<div class="visit-comms"><div class="quick-grid"><a class="quick-card" target="_blank" rel="noopener" href="${meet}"><b>مكالمة فيديو</b><small>غرفة الزيارة ${v.id}</small></a><a class="quick-card" target="_blank" rel="noopener" href="${phone?`tel:${phone}`:meet}"><b>مكالمة صوتية</b><small>${phone||"عبر غرفة الاجتماع"}</small></a><button class="quick-card" type="button" data-copy-invite="${meet}"><b>نسخ رابط الاجتماع</b><small>للمشاركة مع الطرف الآخر</small></button></div><section class="panel"><h3>رسائل الزيارة</h3><div class="visit-chat">${msgs.length?msgs.map(m=>`<article><b>${esc(m.senderName)}</b><small>${esc(m.createdAt)}</small><p>${esc(m.text)}</p></article>`).join(""):"لا توجد رسائل بعد."}</div><form class="modal-form" data-form="visit-message"><input type="hidden" name="visitId" value="${esc(v.id)}"><label>رسالة جديدة<textarea name="message" required placeholder="اكتب رسالة مرتبطة بهذه الزيارة"></textarea></label><button class="btn-primary">إرسال الرسالة</button></form></section></div>`}
  function visitActions(v){const r=visitReport(v);let b=`<button class="action-btn primary" data-visit-comms="${v.id}">تواصل</button>`;if(r)b+=` <button class="action-btn primary" data-view-report="${r.id}">عرض التقرير</button>`;if(canWriteReport(v))b+=` <button class="action-btn primary" data-action="visit-report:${v.id}">تعبئة التقرير</button>`;return b}
  function meetingUrl(m){return m.url||`https://meet.jit.si/${m.room}`}
  function meetingInvitees(m){return (m.invitees||[]).map(id=>staff.find(s=>cleanId(s.identity)===cleanId(id))?.name||users.find(u=>cleanId(u.id)===cleanId(id))?.name||id).join("، ")||"كل الفريق"}
  function meetingsPage(){const rows=meetings.filter(m=>session.role==="admin"||!m.companyOwnerId||m.companyOwnerId===ownerId()||m.createdBy===session.id).map(m=>[m.title,fmtDate(m.scheduledAt),meetingInvitees(m),m.createdByName||"—",`<a class="action-btn primary" target="_blank" rel="noopener" href="${meetingUrl(m)}">دخول</a> <button class="action-btn" data-copy-invite="${meetingUrl(m)}">نسخ</button> <button class="action-btn" data-share-invite="${meetingUrl(m)}" data-share-label="${esc(m.title)}">مشاركة</button>`]);return head("الاجتماعات","إنشاء اجتماعات ودعوة أعضاء الفريق",["owner","company_admin","admin"].includes(session.role)?'<button class="btn-primary" data-action="meeting">اجتماع جديد</button>':"")+(rows.length?table(["العنوان","الموعد","المدعوون","المنشئ","الإجراء"],rows):empty("لا توجد اجتماعات","أنشئ اجتماعًا جديدًا وشارك رابطه مع الأعضاء."))}
  function meetingForm(){const members=[...staff.filter(s=>sameCompany(s)),...users.filter(u=>["owner","company_admin","technician"].includes(u.role))],opts=members.map(m=>`<label class="check"><input type="checkbox" name="invitees" value="${esc(m.identity||m.id)}"> ${esc(m.name)} - ${roles[m.role]||m.role}</label>`).join("")||"<p>لا يوجد أعضاء متاحون.</p>";return `<form class="modal-form" data-form="meeting"><label>عنوان الاجتماع<input name="title" required placeholder="مثال: تنسيق زيارة عاجلة"></label><label>الموعد<input name="scheduledAt" type="datetime-local" required></label><label>ملاحظات<textarea name="notes" placeholder="موضوع الاجتماع أو تعليمات مختصرة"></textarea></label><fieldset class="item-picker"><legend>دعوة الأعضاء</legend>${opts}</fieldset><button class="btn-primary">إنشاء الاجتماع</button></form>`}
  function reportDetails(r){const v=visits.find(x=>x.id===r.visitId)||{},c=contracts.find(x=>x.id===r.contractId)||{};const quoteBtn=["owner","company_admin","admin"].includes(session.role)?`<div class="contract-actions"><button class="btn-primary" data-action="quote-from-report:${r.id}">إنشاء عرض سعر من التقرير</button></div>`:"";return `<div class="contract-document visit-report-doc"><div class="contract-topline"><span class="contract-type">تقرير زيارة فنية</span>${badge(r.status||"بانتظار اعتماد العميل")}</div><div class="contract-title"><div><span>رقم التقرير</span><b>${r.id}</b></div><strong>${r.technician||r.technicianId||"الفني"}</strong></div><div class="contract-summary"><div><small>العقد</small><b>${r.contractId||"زيارة كشفية"}</b></div><div><small>الطرف الثاني</small><b>${partyLabel(r)}</b></div><div><small>الموقع</small><b>${v.building?.name||r.buildingName||"غير محدد"}</b></div><div><small>موعد الزيارة</small><b>${fmtDate(v.scheduledAt)}</b></div><div><small>تاريخ التقرير</small><b>${r.createdAt||"غير محدد"}</b></div><div><small>حالة المصعد</small><b>${r.elevatorStatus||"غير محدد"}</b></div></div><section class="contract-section"><h3>الأعمال المنفذة</h3><p>${r.workDone||"لا توجد تفاصيل."}</p></section><section class="contract-section"><h3>الأعطال والملاحظات الفنية</h3><p>${r.issues||"لا توجد ملاحظات."}</p></section><section class="contract-section"><h3>قطع الغيار المطلوبة / المستخدمة والتوصيات</h3><p>${r.parts||"لا توجد قطع مسجلة."}</p><p>${r.recommendations||"لا توجد توصيات."}</p></section><section class="contract-section"><h3>صور أو روابط مرفقة</h3><p>${r.attachments||"لا توجد مرفقات."}</p></section>${companyStamp()}<div class="form-note decision-note">هذا التقرير محفوظ للعرض فقط ولا يمكن تعديله بعد إرساله.</div>${quoteBtn}${pdfAction("report",r.id)}</div>`}
  function reportForm(v){const c=contracts.find(x=>x.id===v.contractId)||{};return `<form class="modal-form visit-report-form" data-form="visit-report"><input type="hidden" name="visitId" value="${esc(v.id)}"><div class="form-note">سيتم حفظ التقرير نهائيًا بعد الإرسال، ولن يمكن تعديله لاحقًا.</div><fieldset class="item-picker"><legend>بيانات الزيارة</legend><div class="report-details"><dl><dt>الزيارة</dt><dd>${v.id}</dd><dt>العقد</dt><dd>${v.contractId||"زيارة كشفية قبل العقد"}</dd><dt>الطرف الثاني</dt><dd>${partyLabel(v)}</dd><dt>الموقع</dt><dd>${v.building?.name||"غير محدد"} ${v.building?.district||""}</dd><dt>الموعد</dt><dd>${fmtDate(v.scheduledAt)}</dd></dl></div></fieldset><label>حالة المصعد بعد الزيارة<select name="elevatorStatus" required><option>يعمل بشكل طبيعي</option><option>يعمل مع ملاحظات</option><option>متوقف عن العمل</option><option>يحتاج زيارة إضافية</option></select></label><label>الأعمال المنفذة<textarea name="workDone" required placeholder="اكتب ما تم تنفيذه أثناء الزيارة"></textarea></label><label>الأعطال أو الملاحظات الفنية<textarea name="issues" placeholder="اكتب الأعطال أو الملاحظات إن وجدت"></textarea></label><label>القطع المستخدمة أو المطلوبة<textarea name="parts" placeholder="مثال: حساس باب، زيت، لوحة تحكم..."></textarea></label><label>التوصيات<textarea name="recommendations" placeholder="توصيات الصيانة أو السلامة"></textarea></label><label>روابط صور أو مرفقات<textarea name="attachments" placeholder="يمكن لصق روابط صور أو ملفات هنا"></textarea></label><button class="btn-primary">إرسال التقرير النهائي</button></form>`}
  function scoutingVisitForm(){return `<form class="modal-form" data-form="scouting-visit"><fieldset class="item-picker"><legend>بيانات العميل والمنشأة</legend><label>هوية العميل<input name="clientId" data-client-id></label><label>اسم العميل<input name="clientName"></label><label>الرقم الموحد للمنشأة<input name="clientCompanyUnifiedNumber" data-company-number></label><label>اسم المنشأة<input name="clientCompanyName"></label><div data-client-preview class="client-preview">أدخل الهوية أو الرقم الموحد لجلب البيانات المسجلة.</div></fieldset><fieldset class="item-picker"><legend>موقع الكشف</legend><label>اسم المبنى<input name="buildingName" required></label><label>الحي<input name="buildingDistrict" required></label><label>رابط الخريطة<input name="buildingMapUrl" type="url"></label><label>جوال المسؤول<input name="buildingGuardMobile"></label></fieldset>${elevatorFields()}<label>موعد الزيارة الكشفية<input name="scheduledAt" type="datetime-local" required></label><label>ملاحظات أولية<textarea name="notes"></textarea></label><button class="btn-primary">إنشاء وإسناد تلقائي</button></form>`}
  function quoteForm(r=null){const detail=r?`قطع الغيار المطلوبة: ${r.parts||"غير محدد"}\nالتوصيات: ${r.recommendations||"غير محدد"}\nمرجع التقرير: ${r.id}`:"";return `<form class="modal-form" data-form="quote">${r?`<input type="hidden" name="reportId" value="${esc(r.id)}">`:""}<fieldset class="item-picker"><legend>بيانات العميل والمنشأة</legend><label>هوية العميل<input name="clientId" data-client-id value="${esc(r?.clientId)}"></label><label>اسم العميل<input name="clientName" value="${esc(r?.clientName)}"></label><label>الرقم الموحد للمنشأة<input name="clientCompanyUnifiedNumber" data-company-number value="${esc(r?.clientCompanyUnifiedNumber)}"></label><label>اسم المنشأة<input name="clientCompanyName" value="${esc(r?.clientCompanyName)}"></label><label>العميل الظاهر في العرض<input name="client" value="${esc(r?.clientCompanyName||r?.clientName)}" required></label><div data-client-preview class="client-preview">أدخل الهوية أو الرقم الموحد لجلب البيانات المسجلة.</div></fieldset><label>العنوان<input name="title" required value="${r?"عرض سعر بناء على تقرير كشف":""}"></label>${elevatorFields()}${itemPicker("quote")}${quotePartsPicker()}${customItems()}<label>قيمة أساسية قبل الضريبة<input name="value" type="number" min="0" step="0.01" value="0" required></label>${quoteTotalsBox()}<label>التفاصيل<textarea name="details">${esc(detail)}</textarea></label><button class="btn-primary">حفظ وتوجيه العرض للعميل</button></form>`}
  const pdfAction=(type,id)=>`<div class="contract-actions pdf-actions"><button class="btn-primary" data-pdf-doc="${type}" data-pdf-id="${id}">حفظ / مشاركة PDF</button></div>`;
  function quoteDetails(q){const subtotal=Number(q.subtotal??q.value??0),tax=Number(q.taxAmount??subtotal*quoteTaxRate),total=Number(q.totalWithTax??subtotal+tax);return `<div class="contract-document"><div class="contract-topline"><span class="contract-type">عرض سعر</span>${badge(q.status||"بانتظار الرد")}</div><div class="contract-title"><div><span>رقم العرض</span><b>${q.id}</b></div><strong>${money(total)}</strong></div><div class="contract-summary"><div><small>العميل</small><b>${q.client||q.clientCompanyName||"غير محدد"}</b></div><div><small>العنوان</small><b>${q.title||"عرض سعر"}</b></div><div><small>تاريخ الإصدار</small><b>${q.createdAt||"غير محدد"}</b></div><div><small>مرجع الكشف</small><b>${q.reportId||"—"}</b></div><div><small>الإجمالي قبل الضريبة</small><b>${money(subtotal)}</b></div><div><small>ضريبة القيمة المضافة 15%</small><b>${money(tax)}</b></div><div><small>الإجمالي شامل الضريبة</small><b>${money(total)}</b></div></div>${elevatorSection(q.elevatorInfo)}<section class="contract-section"><h3>قطع الغيار بأقل أسعار الموردين</h3>${renderTerms(q.partsItems,"لا توجد قطع غيار في العرض.")}</section><section class="contract-section"><h3>البنود الافتراضية</h3>${renderTerms(q.items,"لا توجد بنود.")}</section><section class="contract-section"><h3>البنود الإضافية</h3>${renderTerms(q.customItems,"لا توجد بنود إضافية.")}</section><section class="contract-section"><h3>التفاصيل</h3><p>${q.details||"لا توجد تفاصيل."}</p></section>${companyStamp()}${pdfAction("quote",q.id)}</div>`}
  function claimDetails(cl){const c=contracts.find(x=>x.id===cl.contractId)||{};return `<div class="contract-document"><div class="contract-topline"><span class="contract-type">مستخلص مالي</span>${badge(cl.status||"قيد المراجعة")}</div><div class="contract-title"><div><span>رقم المستخلص</span><b>${cl.id}</b></div><strong>${money(cl.value)}</strong></div><div class="contract-summary"><div><small>العقد</small><b>${cl.contractId||"غير محدد"}</b></div><div><small>الطرف الثاني</small><b>${contractLabel(c)}</b></div><div><small>الفترة</small><b>${cl.period||"غير محددة"}</b></div><div><small>تاريخ الإنشاء</small><b>${cl.createdAt||"غير محدد"}</b></div></div><section class="contract-section"><h3>بيان المستخلص</h3><p>مستخلص عن الفترة الموضحة أعلاه بمبلغ إجمالي ${money(cl.value)} وفق بيانات العقد والخدمات المسجلة في النظام.</p></section>${companyStamp()}${pdfAction("claim",cl.id)}</div>`}
  function docPayload(type,id){let title="مستند",body="",shareText="";if(type==="contract"){const c=contracts.find(x=>x.id===id);if(c){title=`عقد ${c.id} - ${contractLabel(c)}`;body=contractDetails(c);shareText=`${title} بصيغة PDF`}}if(type==="ticket"){const t=tickets.find(x=>x.id===id);if(t){title=`بلاغ ${t.id} - ${t.clientCompanyName||t.clientName||"عميل"}`;body=ticketDetails(t);shareText=`${title} بصيغة PDF`}}if(type==="report"){const r=reports.find(x=>x.id===id);if(r){title=`تقرير زيارة ${r.id}`;body=reportDetails(r);shareText=`${title} بصيغة PDF`}}if(type==="quote"){const q=quotes.find(x=>x.id===id);if(q){title=`عرض سعر ${q.id} - ${q.client||"عميل"}`;body=quoteDetails(q);shareText=`${title} بصيغة PDF`}}if(type==="claim"){const cl=read("misadClaims").find(x=>x.id===id);if(cl){title=`مستخلص ${cl.id}`;body=claimDetails(cl);shareText=`${title} بصيغة PDF`}}return {title,body,shareText:shareText||title}}
